#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode* prev;
    ListNode* next;
    ListNode(int x) : val(x), prev(nullptr), next(nullptr) {}
};

class Solution {
public:
    ListNode* deleteDuplicates(ListNode* head) {
        ListNode* cur = head;
        while (cur && cur->next) {
            if (cur->val == cur->next->val) {
                ListNode* dup = cur->next;
                ListNode* nxt = dup->next;
                cur->next = nxt;
                if (nxt) nxt->prev = cur;
                delete dup; // optional cleanup
            } else {
                cur = cur->next;
            }
        }
        return head;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    if (!(cin >> t)) return 0;
    while (t--) {
        int n; cin >> n;
        vector<int> vals(n);
        for (int i = 0; i < n; ++i) cin >> vals[i];
        // build doubly linked list
        ListNode* head = nullptr;
        ListNode* prev = nullptr;
        for (int v : vals) {
            ListNode* node = new ListNode(v);
            if (!head) head = node;
            else {
                prev->next = node;
                node->prev = prev;
            }
            prev = node;
        }
        Solution sol;
        ListNode* new_head = sol.deleteDuplicates(head);
        // output
        ListNode* cur = new_head;
        bool first = true;
        while (cur) {
            if (!first) cout << ' ';
            cout << cur->val;
            first = false;
            cur = cur->next;
        }
        if (t) cout << '\n';
        // optional: free memory
        cur = new_head;
        while (cur) {
            ListNode* nxt = cur->next;
            delete cur;
            cur = nxt;
        }
    }
    return 0;
}
